```shell
./src/bin/lfortran --rename-symbol --line=18 --column=22 tests/function_call1.f90 | jq
```

```json
[
  {
    "kind": 1,
    "location": {
      "range": {
        "start": {
          "character": 5,
          "line": 8
        },
        "end": {
          "character": 25,
          "line": 12
        }
      },
      "uri": "uri"
    },
    "name": "eval_1d"
  },
  {
    "kind": 1,
    "location": {
      "range": {
        "start": {
          "character": 7,
          "line": 4
        },
        "end": {
          "character": 28,
          "line": 4
        }
      },
      "uri": "uri"
    },
    "name": "eval_1d"
  }
]
```

If we look at the text of [the file](https://github.com/lfortran/lfortran/blob/main/tests/function_call1.f90):

```typescript
module module_function_call1
    type :: softmax
    contains
      procedure :: eval_1d
    end type softmax
  contains
  
    pure function eval_1d(self, x) result(res)
      class(softmax), intent(in) :: self
      real, intent(in) :: x(:)
      real :: res(size(x))
    end function eval_1d
  
    pure function eval_1d_prime(self, x) result(res)
      class(softmax), intent(in) :: self
      real, intent(in) :: x(:)
      real :: res(size(x))
      res = self%eval_1d(x)
    end function eval_1d_prime
end module module_function_call1
```

, the correct ranges should be the following:
1. start: line=4, character=20; end: line=4, character=26
2. start: line=8, character=19; end: line=25, character=25
3. start: line=12, character=18; end: line=12, character=24
